targets.expr:
sum(
    count_over_time (
        {app="openformulieren"}
        |= "submission_completed"
        | json event
        | event = `submission_completed` 
        [$__range]
    )
) or vector(0)

sum(
    count_over_time (
        {app="openformulieren-worker"}
        |= "registration"
        | json event="event", action="action"
        | event = `registration_success` 
        | action = `registrations.main_registration`
        [$__range]
    )
) or vector(0)

sum(
    count_over_time (
        {app="objecten"}
        |= "object_created"
        | json event
        | event = `object_created` 
        [$__range]
    ) 
) or vector(0)

sum(
    count_over_time (
        {app="opennotificaties-worker"}
        |= "task_succeeded"
        | json event
        | event="task_succeeded"
        [$__range]
    )
) or vector(0)

sum(
    count_over_time (
        {app="openzaak"}
        |= "zaak_created"
        | json event
        | event = `zaak_created` 
        [$__range]
    ) 
) or vector(0)

sum by (public_reference)(
  count_over_time(
    {app="openformulieren-worker"}
    |= "registration"
    | json event="event", action="action", public_reference="public_reference"
    | event="registration_failure"
    | action="registrations.main_registration"
    [$__range]
    ) 
)

sum(
    count_over_time (
        {app="opennotificaties-worker"}
        |= "notification_"
        | json event
        | event=~"notification_failed|notification_error"
        [$__range]
    )

) or vector(0)

1 - sum(
    count_over_time (
        {app="openformulieren-worker"}
        |= "registration"
        | json event="event", action="action"
        | event = `registration_success` 
        | action = `registrations.main_registration`
        [1h]
    )
) / sum(
    count_over_time (
        {app="openformulieren"}
        |= "submission_completed"
        | json event
        | event = `submission_completed` 
        [1h]
    )
)

count by (plugin, event) (
  sum by (plugin, event, public_reference) (
    count_over_time(
      {app="openformulieren-worker"}
      |= "registration_"
      | json event="event", plugin="plugin", public_reference="public_reference", trigger="trigger"
      | event=~"registration_failure|registration_success"
      [$__range]
    )
  )
)

sum by(subscription_callback, resource) (
  count_over_time(
    {app="opennotificaties-worker"} 
    |="notification_successful"
    | json event="event", subscription_callback="subscription_callback", resource="resource"
    | event="notification_successful" 
    [$__range]
  )
)
